class Solution:
    def __init__(self):
        self.visited = set()
    def solve(self, edges, n, m):
        for edge in edges:
            if not edge[0] in self.visited:
                self.dfs(edge[0], edges)
        print(len(self.visited))
    def dfs(self, node, edges):
        self.visited.add(node)
        for edge in edges:
            if edge[0] == node and edge[1] not in self.visited:
                self.dfs(edge[1], edges)

